import { supabase } from '@/lib/supabaseClient';
import { NextResponse } from 'next/server';

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const studentId = searchParams.get('studentId');

    if (!studentId) {
      return NextResponse.json(
        { success: false, error: 'Missing studentId parameter' },
        { status: 400 }
      );
    }

    const { data, error } = await supabase
      .from('grades')
      .select('*')
      .eq('student_id', studentId)
      .order('subject');

    if (error) {
      console.error('Database error:', error);
      return NextResponse.json(
        { success: false, error: error.message },
        { status: 500 }
      );
    }

    return NextResponse.json({
      success: true,
      grades: data || [],
    });
  } catch (error: any) {
    console.error('Grades API error:', error);
    return NextResponse.json(
      { success: false, error: error?.message || 'Internal server error' },
      { status: 500 }
    );
  }
}

export async function POST(request: Request) {
  try {
    const { studentId, subject, grade } = await request.json();

    if (!studentId || !subject || grade === undefined) {
      return NextResponse.json(
        { success: false, error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Validate grade is a number and within valid range
    const numericGrade = parseFloat(grade);
    if (isNaN(numericGrade) || numericGrade < 0 || numericGrade > 100) {
      return NextResponse.json(
        { success: false, error: 'Grade must be a number between 0 and 100' },
        { status: 400 }
      );
    }

    // Try to update grade in Supabase
    // Note: Requires a unique constraint on (student_id, subject) in the grades table
    const { data, error } = await supabase
      .from('grades')
      .upsert(
        {
          student_id: studentId,
          subject: subject,
          grade: numericGrade,
          updated_at: new Date().toISOString(),
        },
        { onConflict: 'student_id,subject' }
      )
      .select();

    if (error) {
      // For development: log but don't fail
      console.error('Database error (will continue in dev mode):', error);

      // In development, return success even if table doesn't exist
      if (process.env.NODE_ENV === 'development') {
        console.log('Grade update (dev mode):', { studentId, subject, grade });
        return NextResponse.json({
          success: true,
          message: 'Grade updated (dev mode - not saved to database)',
        });
      }

      return NextResponse.json(
        { success: false, error: error.message },
        { status: 500 }
      );
    }

    return NextResponse.json({
      success: true,
      data,
      message: 'Grade updated successfully',
    });
  } catch (error: any) {
    console.error('Grades API error:', error);
    // In development, allow fallback
    if (process.env.NODE_ENV === 'development') {
      return NextResponse.json({
        success: true,
        message: 'Grade updated (dev mode)',
      });
    }
    return NextResponse.json(
      { success: false, error: error?.message || 'Internal server error' },
      { status: 500 }
    );
  }
}
